import{_ as n,o as a,c as l,j as e}from"./chunks/framework.CbHyKbeV.js";const u=JSON.parse('{"title":"Метафизика тайм-менеджмента","description":"","frontmatter":{"title":"Метафизика тайм-менеджмента","date":"2022-10-16T00:00:00.000Z"},"headers":[],"relativePath":"posts/2022-10-16-timemanagement.md","filePath":"posts/2022-10-16-timemanagement.md"}'),s={name:"posts/2022-10-16-timemanagement.md"};function m(o,t,p,r,i,c){return a(),l("div",null,[...t[0]||(t[0]=[e("p",null,"Время - категория относительная, мера движения одних вещей относительно других и можно с уверенностью заявить что как феномена его не существует, поэтому речь по сути идет об управлении вниманием. Умении удерживать внимание на определенном пространстве и переключаться между пространствами. Я умышленно не употребляю слово объект, поскольку это не отражает сути и термин довольно плоский. Пространство, как некий объем (тела, души, сознания), требует навыка распределенного внимания и более жизненно.",-1),e("p",null,"Итак, мы определились с основным инструментарием - это управление пространственным вниманием.",-1),e("p",null,'Продолжая движение из плоского мира целей, желаний, событий, из, так называемого, "клипового мышления" в мир ситуаций, включенности и непрерывного движения, давайте введем термин "путь". Путь определяется намерением. А намерение это по сути взаимное притяжение того пространства где мы находимся с тем пространством, где наше внимание.',-1),e("p",null,'Намерение и пространственное внимание взамен плоских и узких целей и фиксации на объектах порождают мышление в четырех изменениях, где четвертым измерением является "ход вещей", который принято называть временем, а так же здравую оценку ситуации и поведение, которое обеспечит ход вещей согласно главной задаче.',-1),e("p",null,'Разумеется, другие люди, социальные модели, правила и законы социума, ядро личности так или иначе будут влиять на ситуации, но если представить это как некую внешнюю сферу, внешний интерфейс, то внутри есть еще одно ядро - субъективная реальность. В противовес социальной реальности оно живет по другим законам и правилам. Это и есть тот, всеми искомый "источник", точка подзарядки, соединение с собой. И из этой субъективной реальности мы можем влиять на свои состояния, мысли, чувства, эмоции. Как око тайфуна, это пространство часто называют "внутренний стержень", на который всегда можно опереться и черпать жизненный потенциал даже (и особенно) в трудных жизненых ситуациях.',-1),e("p",null,"Механизм работы с субъективным пространством тот что что и с социальным - через намерение-притяжение.",-1),e("p",null,"Огромное количество людей лишено контакта с этим внутренним стержнем и поэтому в целях синергии и общего блага влиять на них можно и нужно с помощью создания единого мнения в каждой субъективной реальности с помощью моделей, правил, законов и пропоганды.",-1)])])}const _=n(s,[["render",m]]);export{u as __pageData,_ as default};
